class Solution:
    def minimumRightShifts(self, nums: List[int]) -> int:
        n = len(nums)
        # Find the pivot point where nums[i] > nums[i+1]
        pivot = -1
        for i in range(n - 1):
            if nums[i] > nums[i + 1]:
                pivot = i
                break

        # If no pivot is found, the array is already sorted
        if pivot == -1:
            return 0

        # Check if the array can be rotated to form a sorted array
        # The part after the pivot must be sorted and the last element must be <= first element
        if nums[-1] > nums[0]:
            return -1

        # Check if the array from pivot+1 to end is sorted
        for i in range(pivot + 1, n - 1):
            if nums[i] > nums[i + 1]:
                return -1

        # The number of right shifts needed is (n - pivot - 1)
        return n - pivot - 1
